    bodyHeadings: {"data": {"ja": "Quiet Luxuryとは？2億回再生とノーロゴ需要のデータ", "en": "What is Quiet Luxury? 200M views and the no-logo surge"}, "explanation": {"ja": "なぜ今響く？インフルエンサー疲れと日本の民藝", "en": "Why it resonates now: influencer fatigue and Japan's Mingei"}, "practice": {"ja": "Quiet Luxuryの始め方——ワードローブ3つの実践", "en": "How to start Quiet Luxury: 3 wardrobe practices"}, "cta": {"ja": "まとめ：Quiet Luxuryは「素材とシルエット」で選ぶ", "en": "The takeaway: choose by material and silhouette"}},
    thumbnail: "/images/posts/004/004-thumbnail.jpg",
